content.text:
/**
 * 事实台账面板
 * 支持按类型/角色/章节筛选，伏笔状态管理，点击跳转章节
 * 新增伏笔看板视图
 */

import { useState, useEffect } from 'react'
import {
  List,
  Tag,
  Tabs,
  Empty,
  Spin,
  Button,
  message,
  Select,
  Input,
  Card,
  Badge,
  Space,
  Tooltip,
  Modal,
  Form,
  InputNumber,
  Switch,
  Alert,
  Row,
  Col,
} from 'antd'
import {
  ThunderboltOutlined,
  FireOutlined,
  GiftOutlined,
  TeamOutlined,
  BulbOutlined,
  ReloadOutlined,
  SearchOutlined,
  FilterOutlined,
  EyeOutlined,
  CheckOutlined,
  ExclamationCircleOutlined,
  DragOutlined,
} from '@ant-design/icons'
import factsStore, { Fact } from '../db'
import factExtractor from '../services/factExtractor'

const { TabPane } = Tabs

type FactType = 'all' | 'power' | 'item' | 'relation' | 'foreshadow'

const typeLabels: Record<FactType, { label: string; icon: React.ReactNode; color: string }> = {
  all: { label: '全部', icon: <ThunderboltOutlined />, color: 'default' },
  power: { label: '战力', icon: <FireOutlined />, color: 'red' },
  item: { label: '物品', icon: <GiftOutlined />, color: 'gold' },
  relation: { label: '关系', icon: <TeamOutlined />, color: 'blue' },
  foreshadow: { label: '伏笔', icon: <BulbOutlined />, color: 'purple' },
}

type ForeshadowStatus = '铺设中' | '待回收' | '已回收'

interface ForeshadowItem {
  id: string
  description: string
  setupChapter: number
  payoffChapter?: number
  status: ForeshadowStatus
  relatedCharacters: string[]
  type: '剧情伏笔' | '人物伏笔' | '世界观伏笔'
  isOverdue?: boolean // 超过10章未回收
}

interface FactsPanelProps {
  projectRoot?: string | null
}

const FactsPanel: React.FC<FactsPanelProps> = ({ projectRoot }) => {
  const [activeTab, setActiveTab] = useState<FactType | 'kanban'>('all')
  const [facts, setFacts] = useState<Fact[]>([])
  const [allFacts, setAllFacts] = useState<Fact[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [filterCharacter, setFilterCharacter] = useState<string>('')
  const [filterChapter, setFilterChapter] = useState<number | undefined>(undefined)
  const [showFilters, setShowFilters] = useState(false)
  const [characters, setCharacters] = useState<string[]>([])
  const [currentChapter, setCurrentChapter] = useState<number>(1)

  // 伏笔看板数据
  const [foreshadowItems, setForeshadowItems] = useState<ForeshadowItem[]>([])
  const [showAddForeshadow, setShowAddForeshadow] = useState(false)
  const [form] = Form.useForm()

  // 加载事实
  const loadFacts = async () => {
    setLoading(true)
    try {
      const result = await factsStore.getFacts(undefined, projectRoot)
      setAllFacts(result)

      // 提取所有角色名
      const charNames = Array.from(
        new Set(result.map(f => f.subject).filter(Boolean))
      ).sort() as string[]
      setCharacters(charNames)

      applyFilters(result)

      // 加载伏笔看板（确保 allFacts 已更新）
      if (projectRoot) {
        // 使用 setState 回调确保 allFacts 已更新后再调用
        setAllFacts(prev => {
          // 延迟执行 loadForeshadowKanban
          setTimeout(() => loadForeshadowKanban(), 0)
          return result
        })
      }
    } catch (error) {
      message.error('加载事实失败')
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  // 加载伏笔看板
  const loadForeshadowKanban = async () => {
    if (!projectRoot) return
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        // 获取当前最大章节数（用于判断超期）
        const currentMaxChapter = getCurrentMaxChapter()

        const items: ForeshadowItem[] = foreshadowList.map((fb, idx) => {
          const setupChapter = Number(fb['setup_chapter'] || 1)
          const payoffChapter = fb['payoff_chapter'] ? Number(fb['payoff_chapter']) : undefined
          const status = (fb['status'] as ForeshadowStatus) || '待回收'
          const isOverdue = !!(status !== '已回收' && !payoffChapter && currentMaxChapter >= setupChapter && (currentMaxChapter - setupChapter) > 10)

          return {
            id: String(fb['id'] || `fs-${idx}`),
            description: String(fb['description'] || ''),
            setupChapter,
            payoffChapter,
            status,
            relatedCharacters: (fb['related_characters'] as string[]) || [],
            type: (fb['type'] as ForeshadowItem['type']) || '剧情伏笔',
            isOverdue,
          }
        })

        setForeshadowItems(items)
      }
    } catch (error) {
      console.warn('加载伏笔看板失败:', error)
    }
  }

  // 获取当前最大章节数
  const getCurrentMaxChapter = (): number => {
    // 从 facts 中获取最大的章节号
    const chapters = allFacts
      .map(f => Math.max(f.chapterStart, f.chapterEnd))
      .filter(c => c < 9999)
    return chapters.length > 0 ? Math.max(...chapters) : currentChapter
  }

  // 更新伏笔状态
  const handleUpdateForeshadowStatus = async (
    item: ForeshadowItem,
    newStatus: ForeshadowStatus
  ) => {
    if (!projectRoot) return
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
        const updated = foreshadowList.map(fb => {
          if (fb['id'] === item.id) {
            return { ...fb, status: newStatus }
          }
          return fb
        })
        plotData['伏笔清单'] = updated
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success(`伏笔状态已更新为「${newStatus}」`)
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('更新失败')
    }
  }

  // 添加伏笔
  const handleAddForeshadow = async () => {
    if (!projectRoot) return
    try {
      const values = await form.validateFields()
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        foreshadowList.push({
          id: `FS${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
          description: values.description,
          setup_chapter: values.setupChapter || 1,
          payoff_chapter: values.payoffChapter || undefined,
          status: '铺设中',
          related_characters: values.relatedCharacters || [],
          type: values.type || '剧情伏笔',
        })

        plotData['伏笔清单'] = foreshadowList
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success('伏笔已添加')
        setShowAddForeshadow(false)
        form.resetFields()
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('添加失败')
    }
  }

  // 删除伏笔
  const handleDeleteForeshadow = async (item: ForeshadowItem) => {
    if (!projectRoot) return
    Modal.confirm({
      title: '确认删除此伏笔？',
      content: item.description,
      okText: '确认删除',
      okType: 'danger',
      onOk: async () => {
        try {
          const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
          const result = await window.electronAPI.yaml.read(plotFactsFile)
          if (result.success && result.data) {
            const plotData = result.data as Record<string, unknown>
            const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
            const filtered = foreshadowList.filter(fb => fb['id'] !== item.id)
            plotData['伏笔清单'] = filtered
            const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
            if (!writeResult.success) {
              message.error(`保存失败: ${writeResult.error}`)
              return
            }
            message.success('伏笔已删除')
            await loadForeshadowKanban()
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // 提取当前章节事实
  const extractCurrentChapter = async () => {
    message.info('请在编辑器中选择章节后，使用右侧「AI工具 → 提取事实」功能')
  }

  // 应用筛选
  const applyFilters = (source: Fact[]) => {
    let filtered = source

    if (activeTab !== 'all') {
      filtered = filtered.filter(f => f.type === activeTab)
    }

    if (searchText) {
      const search = searchText.toLowerCase()
      filtered = filtered.filter(
        f =>
          f.subject.toLowerCase().includes(search) ||
          f.object?.toLowerCase().includes(search) ||
          f.content.toLowerCase().includes(search)
      )
    }

    if (filterCharacter) {
      filtered = filtered.filter(
        f => f.subject === filterCharacter || f.object === filterCharacter
      )
    }

    if (filterChapter) {
      filtered = filtered.filter(
        f => f.chapterStart <= filterChapter! && f.chapterEnd >= filterChapter!
      )
    }

    setFacts(filtered)
  }

  // 标签切换时重新筛选
  useEffect(() => {
    if (activeTab !== 'kanban') {
      applyFilters(allFacts)
    }
  }, [activeTab, searchText, filterCharacter, filterChapter])

  // 切换标签时重新加载
  useEffect(() => {
    loadFacts()
  }, [projectRoot])

  // 格式化事实项
  const renderFactItem = (item: Fact) => {
    const typeInfo = typeLabels[item.type as FactType]
    const isForeshadow = item.type === 'foreshadow'

    return (
      <List.Item
        key={item.id}
        style={{ cursor: 'pointer' }}
      >
        <List.Item.Meta
          title={
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
              <Tag color={typeInfo.color}>
                {typeInfo.icon} {typeInfo.label}
              </Tag>
              <strong>{item.subject}</strong>
              {item.object && (
                <>
                  <span style={{ color: '#999' }}>→</span>
                  <strong>{item.object}</strong>
                </>
              )}
              {isForeshadow && (
                <Tag
                  color={
                    item.content.includes('已回收')
                      ? 'green'
                      : item.content.includes('铺设中')
                        ? 'blue'
                        : 'orange'
                  }
                  style={{ marginLeft: 4 }}
                >
                  {item.content.includes('已回收') ? '已回收' : item.content.includes('铺设中') ? '铺设中' : '待回收'}
                </Tag>
              )}
            </div>
          }
          description={
            <div>
              <p style={{ margin: '4px 0' }}>{item.content}</p>
              <div
                style={{
                  fontSize: 12,
                  color: '#999',
                  marginTop: 4,
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <span>
                  第 {item.chapterStart} 章
                  {item.chapterEnd !== item.chapterStart && ` - 第 ${item.chapterEnd} 章`}
                </span>
              </div>
            </div>
          }
        />
      </List.Item>
    )
  }

  // 伏笔看板卡片
  const renderForeshadowCard = (item: ForeshadowItem) => {
    const isOverdue = item.isOverdue

    return (
      <Card
        key={item.id}
        size="small"
        style={{
          marginBottom: 8,
          borderColor: isOverdue ? '#ff4d4f' : undefined,
          borderWidth: isOverdue ? 2 : 1,
        }}
        bodyStyle={{ padding: 10 }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{ flex: 1 }}>
            {isOverdue && (
              <Tag color="red" icon={<ExclamationCircleOutlined />} style={{ marginBottom: 4 }}>
                超期未回收
              </Tag>
            )}
            <div style={{ fontSize: 13, marginBottom: 6 }}>{item.description}</div>
            <div style={{ fontSize: 11, color: '#999' }}>
              <span>铺设：第{item.setupChapter}章</span>
              {item.payoffChapter && (
                <span> → 回收：第{item.payoffChapter}章</span>
              )}
            </div>
            {item.relatedCharacters.length > 0 && (
              <div style={{ marginTop: 4 }}>
                {item.relatedCharacters.slice(0, 3).map(char => (
                  <Tag key={char} color="blue" style={{ fontSize: 10 }}>
                    {char}
                  </Tag>
                ))}
                {item.relatedCharacters.length > 3 && (
                  <Tag style={{ fontSize: 10 }}>+{item.relatedCharacters.length - 3}</Tag>
                )}
              </div>
            )}
          </div>
          <Button
            type="text"
            size="small"
            danger
            icon={<CheckOutlined />}
            onClick={(e) => {
              e.stopPropagation()
              handleDeleteForeshadow(item)
            }}
            style={{ marginLeft: 4 }}
          />
        </div>
      </Card>
    )
  }

  // 伏笔看板三列
  const renderForeshadowKanban = () => {
    const columns: { status: ForeshadowStatus; color: string; items: ForeshadowItem[] }[] = [
      { status: '铺设中', color: 'blue', items: foreshadowItems.filter(f => f.status === '铺设中') },
      { status: '待回收', color: 'orange', items: foreshadowItems.filter(f => f.status === '待回收') },
      { status: '已回收', color: 'green', items: foreshadowItems.filter(f => f.status === '已回收') },
    ]

    const overdueCount = foreshadowItems.filter(f => f.isOverdue).length

    return (
      <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '8px 16px', borderBottom: '1px solid #e8e8e8' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
            <Space>
              <span style={{ fontWeight: 500 }}>伏笔看板</span>
              <Badge count={foreshadowItems.length} style={{ fontSize: 10 }} />
            </Space>
            <Button
              size="small"
              type="primary"
              icon={<BulbOutlined />}
              onClick={() => setShowAddForeshadow(true)}
            >
              添加伏笔
            </Button>
          </div>
          {overdueCount > 0 && (
            <Alert
              message={`有 ${overdueCount} 个伏笔超过10章未回收（已标红）`}
              type="warning"
              showIcon
              style={{ fontSize: 11, marginBottom: 8 }}
            />
          )}
        </div>

        <div style={{ flex: 1, overflow: 'auto', padding: 12 }}>
          <Row gutter={8}>
            {columns.map(col => (
              <Col key={col.status} span={8}>
                <div
                  style={{
                    background: '#f5f5f5',
                    borderRadius: 8,
                    padding: 8,
                    minHeight: 300,
                  }}
                >
                  <div style={{
                    textAlign: 'center',
                    marginBottom: 8,
                    fontWeight: 500,
                    color: col.color,
                  }}>
                    {col.status}
                    <Badge
                      count={col.items.length}
                      style={{ marginLeft: 6 }}
                      color={col.color}
                    />
                  </div>

                  {col.items.length === 0 ? (
                    <div style={{ textAlign: 'center', color: '#999', padding: 20, fontSize: 12 }}>
                      暂无伏笔
                    </div>
                  ) : (
                    <div>
                      {col.items.map(item => (
                        <div
                          key={item.id}
                          style={{ position: 'relative' }}
                          onClick={() => {
                            if (col.status !== '已回收') {
                              const nextStatus: ForeshadowStatus =
                                col.status === '铺设中' ? '待回收' : '已回收'
                              handleUpdateForeshadowStatus(item, nextStatus)
                            }
                          }}
                        >
                          {renderForeshadowCard(item)}
                          {col.status !== '已回收' && (
                            <div style={{
                              position: 'absolute',
                              bottom: -4,
                              left: '50%',
                              transform: 'translateX(-50%)',
                              fontSize: 10,
                              color: '#999',
                              cursor: 'pointer',
                            }}>
                              ↓ 点击推进
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </Col>
            ))}
          </Row>
        </div>

        {/* 添加伏笔 Modal */}
        <Modal
          title="添加伏笔"
          open={showAddForeshadow}
          onCancel={() => setShowAddForeshadow(false)}
          onOk={handleAddForeshadow}
          okText="添加"
        >
          <Form form={form} layout="vertical">
            <Form.Item
              name="description"
              label="伏笔描述"
              rules={[{ required: true, message: '请输入伏笔描述' }]}
            >
              <Input.TextArea rows={2} placeholder="描述这个伏笔的内容..." />
            </Form.Item>
            <Form.Item name="setupChapter" label="铺设章节" initialValue={1}>
              <InputNumber min={1} style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="payoffChapter" label="计划回收章节">
              <InputNumber min={1} placeholder="留空表示未计划" style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="type" label="伏笔类型" initialValue="剧情伏笔">
              <Select
                options={[
                  { value: '剧情伏笔', label: '剧情伏笔' },
                  { value: '人物伏笔', label: '人物伏笔' },
                  { value: '世界观伏笔', label: '世界观伏笔' },
                ]}
              />
            </Form.Item>
            <Form.Item name="relatedCharacters" label="关联角色">
              <Select
                mode="tags"
                placeholder="输入角色名（回车确认）"
                options={characters.map(c => ({ value: c, label: c }))}
              />
            </Form.Item>
          </Form>
        </Modal>
      </div>
    )
  }

  // 统计摘要
  const getSummary = () => {
    const stats = {
      total: allFacts.length,
      power: allFacts.filter(f => f.type === 'power').length,
      item: allFacts.filter(f => f.type === 'item').length,
      relation: allFacts.filter(f => f.type === 'relation').length,
      foreshadow: foreshadowItems.length,
      foreshadowPending: foreshadowItems.filter(f => f.status === '待回收').length,
      foreshadowOverdue: foreshadowItems.filter(f => f.isOverdue).length,
    }
    return stats
  }

  const stats = getSummary()

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '10px 16px', borderBottom: '1px solid #e8e8e8' }}>
        {/* 统计栏 */}
        <div
          style={{
            display: 'flex',
            gap: 8,
            marginBottom: 10,
            flexWrap: 'wrap',
            fontSize: 12,
          }}
        >
          <Badge count={stats.total} showZero color="#1890ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>全部</span>
          </Badge>
          <Badge count={stats.power} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>战力</span>
          </Badge>
          <Badge count={stats.relation} showZero color="#1677ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>关系</span>
          </Badge>
          <Badge count={stats.foreshadow} showZero color="#722ed1" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>
              伏笔
              {stats.foreshadowPending > 0 && ` (${stats.foreshadowPending}待收)`}
            </span>
          </Badge>
          {stats.foreshadowOverdue > 0 && (
            <Badge count={stats.foreshadowOverdue} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
              <span style={{ padding: '2px 8px', background: '#fff1f0', borderRadius: 4, color: '#ff4d4f' }}>
                超期
              </span>
            </Badge>
          )}
        </div>

        {/* 搜索和筛选 */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 10 }}>
          <Input
            placeholder="搜索事实..."
            prefix={<SearchOutlined />}
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            allowClear
            size="small"
            style={{ flex: 1 }}
          />
          <Button
            size="small"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
            type={showFilters ? 'primary' : 'default'}
          >
            筛选
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={loadFacts}
          />
        </div>

        {/* 高级筛选 */}
        {showFilters && (
          <div style={{ marginBottom: 10, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
            <Space direction="vertical" style={{ width: '100%' }}>
              <Select
                placeholder="按角色筛选"
                value={filterCharacter || undefined}
                onChange={(val) => setFilterCharacter(val || '')}
                options={characters.map(c => ({ value: c, label: c }))}
                style={{ width: '100%' }}
                size="small"
                allowClear
                showSearch
              />
              <InputNumber
                placeholder="按章节筛选"
                value={filterChapter}
                onChange={(val) => setFilterChapter(val ?? undefined)}
                min={1}
                style={{ width: '100%' }}
                size="small"
              />
              <Button
                size="small"
                onClick={() => {
                  setFilterCharacter('')
                  setFilterChapter(undefined)
                }}
              >
                清除筛选
              </Button>
            </Space>
          </div>
        )}

        <Tabs
          activeKey={activeTab}
          onChange={(key) => setActiveTab(key as FactType | 'kanban')}
          size="small"
        >
          {Object.entries(typeLabels).map(([key, info]) => (
            <TabPane
              key={key}
              tab={<span>{info.icon} {info.label}</span>}
            />
          ))}
          <TabPane key="kanban" tab={<span><BulbOutlined /> 伏笔看板</span>} />
        </Tabs>
      </div>

      {/* 列表 / 看板 */}
      <div style={{ flex: 1, overflow: 'auto', padding: '0 16px' }}>
        {activeTab === 'kanban' ? (
          renderForeshadowKanban()
        ) : loading ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Spin tip="加载中..." />
          </div>
        ) : facts.length === 0 ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Empty
              description="暂无事实记录"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            />
          </div>
        ) : (
          <List
            dataSource={facts}
            renderItem={renderFactItem}
            size="small"
            style={{ padding: '10px 0' }}
          />
        )}
      </div>
    </div>
  )
}

